import type { LayoutType } from "../../portal/jsonTypes.js";

/**
 * The id and named type of a record to be added or removed from the knowledge graph.
 *
 * @since 5.0
 */
export interface IdTypePair {
  /**
   * The global ID of the record to be added to or removed from the the knowledge graph layer.
   *
   * @since 5.0
   */
  id: string;
  /**
   * the named type of the record to be added or removed from the knowledge graph layer.
   *
   * @since 5.0
   */
  typeName: string;
}

/** @since 5.0 */
export type LayoutMode = Extract<LayoutType, "organic-standard" | "organic-community" | "basic-grid" | "hierarchical-bottom-to-top" | "radial-root-centric" | "tree-left-to-right" | "geographic-organic-standard" | "chronological-mono-timeline" | "chronological-multi-timeline">;

/**
 * Defines the sublayer structure and the named types that will be in the KnowledgeGraphLayer
 *
 * @since 5.0
 */
export interface InclusionModeDefinition {
  /**
   * Specifies whether to create sublayers for each [named type](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/GraphNamedObject/)
   * regardless of whether or not they are included in the `namedTypeDefinition`. If `true` all named types ([EntityType](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/EntityType/) and
   * [RelationshipType](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/RelationshipType/)) will be added as an empty sublayer.
   *
   * @since 5.0
   */
  generateAllSublayers: boolean;
  /**
   * A map of named types and the specific instances
   * of those types to include in the layer.
   *
   * @since 5.0
   */
  namedTypeDefinitions: Map<string, LayerInclusionDefinition>;
}

/**
 * Defines the contents of each specified named type in the [KnowledgeGraphLayer.inclusionModeDefinition](https://developers.arcgis.com/javascript/latest/references/core/layers/KnowledgeGraphLayer/#inclusionModeDefinition) and whether all instance of the named type will be used or a specified subset.
 *
 * @since 5.0
 */
export interface LayerInclusionDefinition {
  /**
   * If `true` all of the instances of the named type will be included regardless of if there is a defined list of members.
   * If `false` only the instances specified in the `members` property will be included.
   *
   * @since 5.0
   */
  useAllData: boolean;
  /**
   * A map of the specific members of the named type to be included.
   * The key is the global ID of the instance.
   *
   * @since 5.0
   */
  members?: Map<string, LayerInclusionMemberDefinition>;
}

/**
 * Defines the list of `members` for a named type in the [KnowledgeGraphLayer.inclusionModeDefinition](https://developers.arcgis.com/javascript/latest/references/core/layers/KnowledgeGraphLayer/#inclusionModeDefinition).
 *
 * @since 5.0
 */
export interface LayerInclusionMemberDefinition {
  /**
   * The global ID of the specific instance of the named type to be included in the layer.
   *
   * @since 5.0
   */
  id: string;
}